function Finance({data,busy,act}:{data:Data;busy:string;act:(a:string,p:Record<string,string>)=>Promise<boolean>}) {
  const openWindows=data.finance.windows.filter(window=>window.status==='OPEN'),[selectedId,setSelectedId]=useState(openWindows[0]?.id||data.finance.windows[0]?.id||""),[modal,setModal]=useState<{type:string;entry?:FolioEntry;window?:FolioWindow;invoice?:ArInvoice}|null>(null); const selected=data.finance.windows.find(window=>window.id===selectedId)||data.finance.windows[0],entries=data.finance.entries.filter(entry=>entry.folio_window_id===selected?.id),canFolio=data.principal.capabilities.includes('FOLIO_WRITE'),canAr=data.principal.capabilities.includes('AR_WRITE'),trial=data.finance.trialBalance;
  return <><section className="finance-kpis"><article><span>GUEST LEDGER</span><strong>{money(Number(trial.guest_ledger))}</strong><p>투숙객 미수 잔액</p></article><article><span>AR LEDGER</span><strong>{money(Number(trial.ar_ledger))}</strong><p>후불 매출채권</p></article><article><span>GROSS REVENUE</span><strong>{money(Number(trial.gross_revenue))}</strong><p>반대전표 반영 매출</p></article><article><span>NET PAYMENTS</span><strong>{money(Number(trial.net_payments))}</strong><p>환불 차감 순수납</p></article></section><div className="finance-layout"><section className="panel folio-windows"><div className="panel-title"><div><h2>폴리오 창</h2><p>고객·회사별 분리 원장</p></div>{canFolio&&<button className="text-action" onClick={()=>setModal({type:'window'})}>＋ 창</button>}</div>{data.finance.windows.map(window=><button key={window.id} className={selected?.id===window.id?'selected':''} onClick={()=>setSelectedId(window.id)}><span><b>W{window.window_no} · {window.name}</b><small>{window.guest_name} · {window.confirmation_no}</small></span><span><strong>{money(Number(window.balance))}</strong><i className={`status ${window.status==='OPEN'?'ready':''}`}>{window.status}</i></span></button>)}</section><section className="panel folio-ledger"><div className="panel-title"><div><h2>{selected?`W${selected.window_no} · ${selected.name}`:'전표 원장'}</h2><p>{selected&&`순액 ${money(Number(selected.net_total))} · 세금 ${money(Number(selected.tax_total))} · 서비스 ${money(Number(selected.service_total))}`}</p></div><div className="ledger-actions">{canFolio&&selected?.status==='OPEN'&&<button onClick={()=>setModal({type:'routing',window:selected})}>라우팅</button>}{canAr&&selected?.status==='OPEN'&&Number(selected.balance)>0&&<button onClick={()=>setModal({type:'ar',window:selected})}>AR 이관</button>}</div></div><div className="ledger-head"><span>일자 / 코드</span><span>설명</span><span>순액·세금</span><span>총액</span><span/></div>{entries.map(entry=><div className="ledger-row" key={entry.id}><span><b>{entry.business_date.slice(5)} · {entry.code}</b><small>{entry.kind}</small></span><span><b>{entry.description}</b><small>{entry.reason||entry.created_by}</small></span><span><b>{money(Number(entry.net_amount))}</b><small>세금 {money(Number(entry.tax_amount))}</small></span><strong className={['PAYMENT','CHARGE_REVERSAL'].includes(entry.kind)?'credit':''}>{['PAYMENT','CHARGE_REVERSAL'].includes(entry.kind)?'−':'+'}{money(Number(entry.amount))}</strong><span className="row-actions">{canFolio&&entry.kind==='CHARGE'&&<button onClick={()=>setModal({type:'split',entry})}>분할</button>}{canFolio&&['CHARGE','PAYMENT'].includes(entry.kind)&&<button onClick={()=>setModal({type:'reverse',entry})}>반대</button>}{canFolio&&entry.kind==='PAYMENT'&&entry.payment_method!=='DIRECT_BILL'&&<button onClick={()=>setModal({type:'refund',entry})}>환불</button>}</span></div>)}{!entries.length&&<div className="empty-state large"><b>전표가 없습니다</b><p>선택한 창에 비용 또는 결제를 전기하세요.</p></div>}</section><section className="panel ar-panel"><div className="panel-title"><div><h2>AR 청구서</h2><p>회사 후불·수납·잔액</p></div><span className="live">APPEND ONLY</span></div>{data.finance.arInvoices.map(invoice=><article key={invoice.id}><span><b>{invoice.invoice_no}</b><small>{invoice.account_name} · 만기 {invoice.due_date}</small></span><span><strong>{money(Number(invoice.balance))}</strong><i className={`status ${invoice.status==='PAID'?'ready':'warn'}`}>{invoice.status}</i></span>{canAr&&Number(invoice.balance)>0&&<button disabled={!!busy} onClick={()=>setModal({type:'ar_payment',invoice})}>수납</button>}</article>)}{!data.finance.arInvoices.length&&<div className="empty-state"><b>AR 청구서 없음</b><p>후불 승인 계정으로 폴리오를 이관하면 생성됩니다.</p></div>}</section></div>{modal&&<FinanceModal mode={modal} data={data} busy={busy} close={()=>setModal(null)} act={act}/>}</>;
}

function FinanceModal({mode,data,busy,close,act}:{mode:{type:string;entry?:FolioEntry;window?:FolioWindow;invoice?:ArInvoice};data:Data;busy:string;close:()=>void;act:(a:string,p:Record<string,string>)=>Promise<boolean>}) { const tomorrow=new Date(`${data.property.business_date}T00:00:00Z`);tomorrow.setUTCDate(tomorrow.getUTCDate()+30);const [form,setForm]=useState({reservationId:mode.window?.reservation_id||data.reservations[0]?.id||"",name:"Company Folio",payeeType:"COMPANY",accountProfileId:"",code:data.finance.transactionCodes[0]?.code||"ROOM",windowId:mode.window?.id||"",targetWindowId:"",amount:String(mode.entry?.amount||mode.invoice?.balance||""),reason:"",dueDate:tomorrow.toISOString().slice(0,10),method:"BANK_TRANSFER",creditLimit:"0"});const set=(key:string,value:string)=>setForm(current=>({...current,[key]:value})),reservationId=mode.entry?.reservation_id||mode.window?.reservation_id||form.reservationId,windows=data.finance.windows.filter(window=>window.reservation_id===reservationId&&window.status==='OPEN'&&window.id!==mode.entry?.folio_window_id),directBill=data.groups.accounts.filter(account=>account.credit_status==='DIRECT_BILL'); const config:Record<string,{title:string;intro:string;action:string}>={window:{title:"폴리오 창 생성",intro:"지불 주체별로 원장을 분리합니다.",action:"create_folio_window"},routing:{title:"거래 코드 라우팅",intro:"이후 동일 코드 전표를 선택한 창으로 자동 라우팅합니다.",action:"create_routing_rule"},split:{title:"전표 분할 이동",intro:"원전표는 수정하지 않고 반대전표와 대상 창 재전기를 동시에 생성합니다.",action:"split_folio_entry"},reverse:{title:"반대전표 생성",intro:"확정 전표는 삭제하지 않습니다. 남은 금액 전체를 반대 전기합니다.",action:"reverse_folio_entry"},refund:{title:"결제 환불",intro:"원결제 한도 안에서 환불 전표를 생성하고 캐셔 실사에 반영합니다.",action:"refund_payment"},ar:{title:"AR 청구 이관",intro:"Guest ledger 잔액을 0으로 만들고 같은 금액을 AR debit으로 옮깁니다.",action:"transfer_to_ar"},ar_payment:{title:"AR 수납",intro:"청구서 잔액 안에서 수납하고 AR credit을 기록합니다.",action:"post_ar_payment"}},current=config[mode.type];return <div className="modal-backdrop"><form className="cashier-modal finance-modal" onSubmit={async event=>{event.preventDefault();const payload={...form,reservationId,entryId:mode.entry?.id||"",windowId:mode.window?.id||form.windowId,invoiceId:mode.invoice?.id||""};if(await act(current.action,payload))close()}}><div className="drawer-head"><div><p>FINANCIAL CONTROL</p><h2>{current.title}</h2></div><button type="button" onClick={close}>×</button></div><p className="form-intro">{current.intro}</p><div className="stack-form">{mode.type==='window'&&<><label><span>예약</span><select value={form.reservationId} onChange={e=>set('reservationId',e.target.value)}>{data.reservations.map(r=><option key={r.id} value={r.id}>{r.confirmation_no} · {r.first_name} {r.last_name}</option>)}</select></label><label><span>창 이름</span><input required value={form.name} onChange={e=>set('name',e.target.value)}/></label><label><span>지불 주체</span><select value={form.payeeType} onChange={e=>set('payeeType',e.target.value)}><option value="GUEST">고객</option><option value="COMPANY">회사</option><option value="TRAVEL_AGENT">여행사</option><option value="GROUP">그룹</option></select></label></>}{mode.type==='routing'&&<><label><span>거래 코드</span><select value={form.code} onChange={e=>set('code',e.target.value)}>{data.finance.transactionCodes.filter(code=>code.category!=='PAYMENT').map(code=><option key={code.id} value={code.code}>{code.code} · {code.name}</option>)}</select></label><label><span>대상 창</span><select required value={form.windowId} onChange={e=>set('windowId',e.target.value)}>{data.finance.windows.filter(window=>window.reservation_id===mode.window?.reservation_id&&window.status==='OPEN').map(window=><option key={window.id} value={window.id}>W{window.window_no} · {window.name}</option>)}</select></label></>}{mode.type==='split'&&<><label><span>분할 금액</span><input type="number" min="0.01" max={mode.entry?.amount} value={form.amount} onChange={e=>set('amount',e.target.value)}/></label><label><span>대상 창</span><select required value={form.targetWindowId} onChange={e=>set('targetWindowId',e.target.value)}><option value="">선택</option>{windows.map(window=><option key={window.id} value={window.id}>W{window.window_no} · {window.name}</option>)}</select></label><label><span>분할 사유</span><input required value={form.reason} onChange={e=>set('reason',e.target.value)}/></label></>}{mode.type==='reverse'&&<label><span>정정 사유</span><input required value={form.reason} onChange={e=>set('reason',e.target.value)}/></label>}{mode.type==='refund'&&<><label><span>환불 금액</span><input type="number" min="0.01" max={mode.entry?.amount} value={form.amount} onChange={e=>set('amount',e.target.value)}/></label><label><span>환불 사유</span><input required value={form.reason} onChange={e=>set('reason',e.target.value)}/></label></>}{mode.type==='ar'&&<><label><span>후불 승인 계정</span><select required value={form.accountProfileId} onChange={e=>set('accountProfileId',e.target.value)}><option value="">선택</option>{directBill.map(account=><option key={account.id} value={account.id}>{account.name} · {account.external_id||account.type}</option>)}</select></label><label><span>만기일</span><input type="date" min={data.property.business_date} value={form.dueDate} onChange={e=>set('dueDate',e.target.value)}/></label><label><span>신용 한도(0=무제한)</span><input type="number" min="0" value={form.creditLimit} onChange={e=>set('creditLimit',e.target.value)}/></label></>}{mode.type==='ar_payment'&&<><label><span>수납 금액</span><input type="number" min="0.01" max={mode.invoice?.balance} value={form.amount} onChange={e=>set('amount',e.target.value)}/></label><label><span>수납 수단</span><select value={form.method} onChange={e=>set('method',e.target.value)}><option value="BANK_TRANSFER">계좌 이체</option><option value="CARD">카드</option><option value="CASH">현금</option></select></label></>}</div><div className="modal-actions"><button type="button" className="secondary" onClick={close}>닫기</button><button className="primary" disabled={!!busy}>{busy?'원장 검증 중…':'확정'}</button></div></form></div> }

function AccountProfileModal({busy,close,act}:{busy:string;close:()=>void;act:(a:string,p:Record<string,string>)=>Promise<boolean>}) { const [form,setForm]=useState({type:"COMPANY",name:"",externalId:"",email:"",phone:"",negotiatedRateCode:"",creditStatus:"CASH",notes:""});const set=(key:string,value:string)=>setForm(current=>({...current,[key]:value}));return <div className="modal-backdrop"><form className="booking-modal" onSubmit={async event=>{event.preventDefault();if(await act('create_account_profile',form))close()}}><div className="drawer-head"><div><p>SALES ACCOUNT</p><h2>세일즈 프로필 생성</h2></div><button type="button" onClick={close}>×</button></div><p className="form-intro">회사 Corp ID, 여행사 IATA, 그룹 Client ID를 외부 ID로 관리하고 협상 요금과 신용 상태를 연결합니다.</p><div className="form-grid"><label><span>프로필 유형</span><select value={form.type} onChange={e=>set('type',e.target.value)}><option value="COMPANY">회사</option><option value="TRAVEL_AGENT">여행사</option><option value="SOURCE">예약 소스</option><option value="GROUP">그룹</option></select></label><label><span>프로필 이름</span><input required value={form.name} onChange={e=>set('name',e.target.value)}/></label><label><span>외부 ID / IATA</span><input value={form.externalId} onChange={e=>set('externalId',e.target.value)}/></label><label><span>협상 요금 코드</span><input value={form.negotiatedRateCode} onChange={e=>set('negotiatedRateCode',e.target.value)}/></label><label><span>이메일</span><input type="email" value={form.email} onChange={e=>set('email',e.target.value)}/></label><label><span>연락처</span><input value={form.phone} onChange={e=>set('phone',e.target.value)}/></label><label><span>신용 상태</span><select value={form.creditStatus} onChange={e=>set('creditStatus',e.target.value)}><option value="CASH">현금/선결제</option><option value="DIRECT_BILL">후불 승인</option><option value="HOLD">신용 보류</option></select></label><label className="span-2"><span>메모</span><textarea value={form.notes} onChange={e=>set('notes',e.target.value)}/></label></div><div className="modal-actions"><button type="button" className="secondary" onClick={close}>닫기</button><button className="primary" disabled={!!busy}>{busy?'저장 중…':'프로필 생성'}</button></div></form></div> }

function BusinessBlockModal({data,busy,close,act}:{data:Data;busy:string;close:()=>void;act:(a:string,p:Record<string,string>)=>Promise<boolean>}) { const departure=new Date(`${data.property.business_date}T00:00:00Z`);departure.setUTCDate(departure.getUTCDate()+2);const [form,setForm]=useState({name:"",code:"",accountProfileId:"",groupProfileId:"",arrivalDate:data.property.business_date,departureDate:departure.toISOString().slice(0,10),status:"TENTATIVE",reservationMethod:"ROOMING_LIST",deductInventory:"true",cutoffDate:data.property.business_date,notes:""});const [allocations,setAllocations]=useState<Record<string,{rooms:string;rate:string}>>(()=>Object.fromEntries(data.inventory.types.map(type=>[type.id,{rooms:"0",rate:String(type.base_rate)}])));const set=(key:string,value:string)=>setForm(current=>({...current,[key]:value}));const accounts=data.groups.accounts.filter(account=>account.type!=="GROUP"),groups=data.groups.accounts.filter(account=>account.type==="GROUP");return <div className="modal-backdrop"><form className="booking-modal block-modal" onSubmit={async event=>{event.preventDefault();const rows=data.inventory.types.map(type=>({roomTypeId:type.id,rooms:Number(allocations[type.id]?.rooms||0),rate:Number(allocations[type.id]?.rate||type.base_rate)})).filter(row=>row.rooms>0);if(await act('create_business_block',{...form,allocations:JSON.stringify(rows)}))close()}}><div className="drawer-head"><div><p>BUSINESS BLOCK</p><h2>그룹 블록 생성</h2></div><button type="button" onClick={close}>×</button></div><p className="form-intro">Deduct 블록은 픽업 전 객실도 하우스 재고에서 홀드합니다. Cutoff 시 미픽업 수량만 자동 반환됩니다.</p><div className="form-grid"><label><span>블록명</span><input required value={form.name} onChange={e=>set('name',e.target.value)}/></label><label><span>블록 코드</span><input placeholder="자동 생성" value={form.code} onChange={e=>set('code',e.target.value)}/></label><label><span>세일즈 계정</span><select value={form.accountProfileId} onChange={e=>set('accountProfileId',e.target.value)}><option value="">연결 없음</option>{accounts.map(account=><option key={account.id} value={account.id}>{account.name} · {account.type}</option>)}</select></label><label><span>그룹 프로필</span><select value={form.groupProfileId} onChange={e=>set('groupProfileId',e.target.value)}><option value="">연결 없음</option>{groups.map(group=><option key={group.id} value={group.id}>{group.name}</option>)}</select></label><label><span>도착일</span><input type="date" required value={form.arrivalDate} onChange={e=>set('arrivalDate',e.target.value)}/></label><label><span>출발일</span><input type="date" required value={form.departureDate} onChange={e=>set('departureDate',e.target.value)}/></label><label><span>Cutoff 일자</span><input type="date" value={form.cutoffDate} onChange={e=>set('cutoffDate',e.target.value)}/></label><label><span>블록 상태</span><select value={form.status} onChange={e=>set('status',e.target.value)}><option value="TENTATIVE">Tentative</option><option value="DEFINITE">Definite</option></select></label><label className="toggle-field span-2"><span>하우스 재고 차감(Deduct)</span><input type="checkbox" checked={form.deductInventory==='true'} onChange={e=>set('deductInventory',String(e.target.checked))}/></label></div><h3 className="subhead modal-subhead">객실 타입 할당</h3><div className="allocation-editor">{data.inventory.types.map(type=><div key={type.id}><span><b>{type.code}</b><small>{type.name} · 물리 {type.physical}실</small></span><label><small>객실 수</small><input type="number" min="0" max={type.physical} value={allocations[type.id]?.rooms||"0"} onChange={e=>setAllocations(current=>({...current,[type.id]:{...current[type.id],rooms:e.target.value}}))}/></label><label><small>그룹 요금</small><input type="number" min="0" value={allocations[type.id]?.rate||"0"} onChange={e=>setAllocations(current=>({...current,[type.id]:{...current[type.id],rate:e.target.value}}))}/></label></div>)}</div><div className="modal-actions"><button type="button" className="secondary" onClick={close}>닫기</button><button className="primary" disabled={!!busy}>{busy?'하우스 재고 검증 중…':'블록 생성'}</button></div></form></div> }

function RoomingEntryModal({block,inventory,busy,close,act}:{block:BusinessBlock;inventory:BlockInventoryRow[];busy:string;close:()=>void;act:(a:string,p:Record<string,string>)=>Promise<boolean>}) { const types=Array.from(new Map(inventory.map(row=>[row.room_type_id,{id:row.room_type_id,code:row.room_type_code,name:row.room_type_name,rate:row.rate}])).values());const [form,setForm]=useState({firstName:"",lastName:"",email:"",phone:"",arrivalDate:block.arrival_date,departureDate:block.departure_date,roomTypeId:types[0]?.id||"",rate:String(types[0]?.rate||0),notes:""});const set=(key:string,value:string)=>setForm(current=>({...current,[key]:value}));return <div className="modal-backdrop"><form className="booking-modal" onSubmit={async event=>{event.preventDefault();if(await act('add_rooming_entry',{blockId:block.id,...form}))close()}}><div className="drawer-head"><div><p>{block.code} · ROOMING LIST</p><h2>투숙객 추가</h2></div><button type="button" onClick={close}>×</button></div><p className="form-intro">명단 등록은 블록을 소비하지 않습니다. ‘예약 픽업’ 시에만 블록 가용을 예약 재고로 원자 변환합니다.</p><div className="form-grid"><label><span>이름</span><input required value={form.firstName} onChange={e=>set('firstName',e.target.value)}/></label><label><span>성</span><input required value={form.lastName} onChange={e=>set('lastName',e.target.value)}/></label><label><span>도착일</span><input type="date" min={block.arrival_date} max={block.departure_date} value={form.arrivalDate} onChange={e=>set('arrivalDate',e.target.value)}/></label><label><span>출발일</span><input type="date" min={block.arrival_date} max={block.departure_date} value={form.departureDate} onChange={e=>set('departureDate',e.target.value)}/></label><label><span>객실 타입</span><select value={form.roomTypeId} onChange={e=>{const type=types.find(item=>item.id===e.target.value);set('roomTypeId',e.target.value);if(type)set('rate',String(type.rate))}}>{types.map(type=><option value={type.id} key={type.id}>{type.code} · {type.name}</option>)}</select></label><label><span>그룹 요금</span><input type="number" min="0" value={form.rate} onChange={e=>set('rate',e.target.value)}/></label><label><span>이메일</span><input type="email" value={form.email} onChange={e=>set('email',e.target.value)}/></label><label><span>연락처</span><input value={form.phone} onChange={e=>set('phone',e.target.value)}/></label></div><div className="modal-actions"><button type="button" className="secondary" onClick={close}>닫기</button><button className="primary" disabled={!!busy}>{busy?'등록 중…':'명단 등록'}</button></div></form></div> }

function BlockInventoryEditModal({row,busy,close,act}:{row:BlockInventoryRow;busy:string;close:()=>void;act:(a:string,p:Record<string,string>)=>Promise<boolean>}) { const [rooms,setRooms]=useState(String(row.current_rooms)),[rate,setRate]=useState(String(row.rate));return <div className="modal-backdrop"><form className="cashier-modal" onSubmit={async event=>{event.preventDefault();if(await act('update_block_inventory',{blockId:row.block_id,roomTypeId:row.room_type_id,stayDate:row.stay_date,rooms,rate}))close()}}><div className="drawer-head"><div><p>{row.stay_date} · {row.room_type_code}</p><h2>블록 할당 조정</h2></div><button type="button" onClick={close}>×</button></div><p className="form-intro">원본 {row.original_rooms}실 · 픽업 {row.picked_up}실. 현재 할당은 픽업보다 낮출 수 없습니다.</p><div className="form-grid"><label><span>현재 할당</span><input type="number" min={row.picked_up} value={rooms} onChange={e=>setRooms(e.target.value)}/></label><label><span>그룹 요금</span><input type="number" min="0" value={rate} onChange={e=>setRate(e.target.value)}/></label></div><div className="modal-actions"><button type="button" className="secondary" onClick={close}>닫기</button><button className="primary" disabled={!!busy}>저장</button></div></form></div> }

function NewReservation({rooms,businessDate,busy,close,act}:{rooms:Room[];businessDate:string;busy:string;close:()=>void;act:(a:string,p:Record<string,string>)=>Promise<boolean>}) {
  const types=Array.from(new Map(rooms.filter(r=>r.active!==0&&r.active!==false).map(r=>[r.room_type_id,{id:r.room_type_id,code:r.room_type_code,name:r.room_type_name}])).values()); const departure=new Date(`${businessDate}T00:00:00Z`);departure.setUTCDate(departure.getUTCDate()+1); const [form,setForm]=useState({firstName:"",lastName:"",email:"",phone:"",arrivalDate:businessDate,departureDate:departure.toISOString().slice(0,10),roomTypeId:types[0]?.id||"",roomId:"",adults:"2",children:"0",source:"Direct",ratePlan:"BAR",nightlyRate:"",eta:"15:00"});
  const set=(key:string,value:string)=>setForm(v=>({...v,[key]:value})); const available=rooms.filter(r=>r.active!==0&&r.active!==false&&r.room_type_id===form.roomTypeId&&r.front_desk_status==='VACANT'&&['CLEAN','INSPECTED'].includes(r.housekeeping_status));
  return <div className="modal-backdrop"><form className="booking-modal" onSubmit={async e=>{e.preventDefault();if(await act('create_reservation',form))close()}}><div className="drawer-head"><div><p>NEW RESERVATION</p><h2>새 예약 만들기</h2></div><button type="button" onClick={close}>×</button></div><p className="form-intro">고객, 일정, 객실을 한 번에 확정합니다. 객실을 선택하면 박 단위 재고가 즉시 잠깁니다.</p><div className="form-grid"><label><span>이름</span><input required value={form.firstName} onChange={e=>set('firstName',e.target.value)}/></label><label><span>성</span><input required value={form.lastName} onChange={e=>set('lastName',e.target.value)}/></label><label><span>이메일</span><input type="email" value={form.email} onChange={e=>set('email',e.target.value)}/></label><label><span>연락처</span><input value={form.phone} onChange={e=>set('phone',e.target.value)}/></label><label><span>도착일</span><input type="date" required value={form.arrivalDate} onChange={e=>set('arrivalDate',e.target.value)}/></label><label><span>출발일</span><input type="date" required value={form.departureDate} onChange={e=>set('departureDate',e.target.value)}/></label><label><span>객실 타입</span><select value={form.roomTypeId} onChange={e=>{set('roomTypeId',e.target.value);set('roomId','')}}>{types.map(t=><option key={t.id} value={t.id}>{t.code} · {t.name}</option>)}</select></label><label><span>객실 배정</span><select value={form.roomId} onChange={e=>set('roomId',e.target.value)}><option value="">나중에 배정</option>{available.map(r=><option key={r.id} value={r.id}>{r.number} · {labels[r.housekeeping_status]}</option>)}</select></label><label><span>예약 채널</span><select value={form.source} onChange={e=>set('source',e.target.value)}><option>Direct</option><option>Booking.com</option><option>Expedia</option><option>Corporate</option></select></label><label><span>도착 예정</span><input type="time" value={form.eta} onChange={e=>set('eta',e.target.value)}/></label></div><div className="modal-actions"><button type="button" className="secondary" onClick={close}>취소</button><button className="primary" disabled={!!busy}>{busy?'예약 확인 중…':'예약 확정'}</button></div></form></div>
}

function CashierModal({mode,busy,close,act}:{mode:"open"|"close";busy:string;close:()=>void;act:(a:string,p:Record<string,string>)=>Promise<boolean>}) { const [amount,setAmount]=useState("0"); const closing=mode==='close'; return <div className="modal-backdrop"><form className="cashier-modal" onSubmit={async e=>{e.preventDefault();const ok=await act(closing?'close_cashier':'open_cashier',closing?{countedAmount:amount}:{openingAmount:amount});if(ok)close()}}><div className="drawer-head"><div><p>{closing?'CASHIER CLOSURE':'CASHIER OPEN'}</p><h2>{closing?'캐셔 마감':'캐셔 개시'}</h2></div><button type="button" onClick={close}>×</button></div><p className="form-intro">{closing?'현재 현금함의 실사 금액을 입력하세요. 시스템 예상액과 차이는 감사 기록에 남습니다.':'교대 시작 시 현금함의 시재금을 입력하세요. 이후 모든 전기와 결제가 이 세션에 귀속됩니다.'}</p><label className="cashier-amount"><span>{closing?'실사 현금':'시재금'}</span><input autoFocus type="number" min="0" step="100" value={amount} onChange={e=>setAmount(e.target.value)}/><b>KRW</b></label><div className="modal-actions"><button type="button" className="secondary" onClick={close}>취소</button><button className="primary" disabled={!!busy}>{busy?'처리 중…':closing?'마감 확정':'개시 확정'}</button></div></form></div> }

function Revenue({data}:{data:Data}) { const dates=Array.from({length:7},(_,index)=>{const day=new Date(`${data.property.business_date}T00:00:00Z`);day.setUTCDate(day.getUTCDate()-6+index);return day.toISOString().slice(0,10)}),values=dates.map(date=>data.finance.entries.filter(entry=>entry.business_date===date&&entry.code==='ROOM').reduce((sum,entry)=>sum+(entry.kind==='CHARGE'?Number(entry.amount):entry.kind==='CHARGE_REVERSAL'?-Number(entry.amount):0),0)),max=Math.max(1,...values),sources=Array.from(data.reservations.reduce((map,reservation)=>map.set(reservation.source,(map.get(reservation.source)||0)+1),new Map<string,number>()).entries()).sort((a,b)=>b[1]-a[1]),total=Math.max(1,data.reservations.length),colors=['#194d45','#4176d8','#8d6ccf','#eba43c','#20a474'];return <div className="two-col revenue-layout"><section className="panel"><div className="panel-title"><div><h2>7일 객실 매출</h2><p>전기된 객실료 순매출 · {money(values.reduce((sum,value)=>sum+value,0))}</p></div><span className="live">LIVE LEDGER</span></div><div className="chart">{values.map((value,index)=><div key={dates[index]} title={`${dates[index]} · ${money(value)}`}><i style={{height:`${Math.max(value?8:2,value/max*100)}%`}}/><span>{dates[index].slice(8)}일</span></div>)}</div></section><section className="panel"><div className="panel-title"><div><h2>채널 믹스</h2><p>전체 예약 생산 비중</p></div></div><div className="channel-list">{sources.map(([name,count],index)=>{const percent=Math.round(count/total*100);return <div key={name}><p><span><i style={{background:colors[index%colors.length]}}/>{name}</span><b>{percent}%</b></p><div><i style={{width:`${percent}%`,background:colors[index%colors.length]}}/></div></div>})}{sources.length===0&&<p className="empty-row">예약 데이터가 없습니다.</p>}</div></section></div> }
function Audit({data,busy,act,onReview}:{data:Data;busy:string;act:(a:string,p:Record<string,string>)=>Promise<boolean>;onReview:(code:string)=>void}) { const checks=data.controls.blockers; const passed=checks.filter(x=>x.count===0).length; const canRun=data.principal.capabilities.includes('EOD_RUN')&&data.controls.canClose; return <section className="panel full audit"><div className="panel-title"><div><h2>영업일 마감 컨트롤</h2><p>{data.property.business_date} · OPERA 방식의 선행 검증 후 객실료를 자동 전기하고 날짜를 전환합니다</p></div><span className={`audit-score ${data.controls.canClose?'ready':''}`}>{passed}/{checks.length} 통과</span></div><div className="posting-preview"><span>자동 객실료 전기 예정</span><strong>{data.controls.pendingRoomPostings}건</strong><small>중복 전기는 데이터베이스에서 차단됩니다</small></div>{checks.map(check=><div className="audit-row" key={check.code}><span className={check.count===0?'pass':check.blocking?'attention':'info'}>{check.count===0?'✓':check.blocking?'!':'i'}</span><div><b>{check.label}</b><small>{check.count===0?'검증 통과':check.blocking?'마감 전 처리가 필요합니다':'마감을 막지 않는 참고 항목입니다'}</small></div><strong>{check.count}건</strong><button type="button" disabled={check.count===0} onClick={()=>onReview(check.code)}>{check.count===0?'완료':'검토'}</button></div>)}{!data.principal.capabilities.includes('EOD_RUN')&&<p className="permission-note">현재 역할에는 영업일 마감 권한이 없습니다.</p>}<button className="primary audit-run" disabled={!canRun||!!busy} onClick={()=>act('run_night_audit',{})}>{busy?'마감 처리 중…':data.controls.canClose?'객실료 전기 및 영업일 마감':`차단 항목 ${checks.filter(x=>x.blocking&&x.count>0).length}개 해결 필요`}</button></section> }
